function esc(value) {
  return String(value || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function titleFromSlug(slug) {
  return slug.split('-').map((part) => caps[part] || part.charAt(0).toUpperCase() + part.slice(1)).join(' ');
}

function list(items) {
  return `<ul class="wi-detail-list">${items.map((item) => `<li>${item}</li>`).join('')}</ul>`;
}

function relatedLinks(slugs) {
  return slugs.map((slug) => `<a href="/seo-pages/${slug}.html">${esc(titleFromSlug(slug))}</a>`).join('');
}

function factPanel(page) {
  const tax = page.refType === 'tax' || page.refType === 'epf'
    ? '<p><strong>Transition rule:</strong> AY 2026-27 covers FY 2025-26 and continues under the Income-tax Act, 1961. The Income-tax Act 2025 Tax Year language applies for income earned from 1 April 2026 onward.</p>'
    : '';
  const gst = page.refType === 'gst'
    ? '<p><strong>GST caution:</strong> GST rates, exemptions, place-of-supply treatment and waiver windows should be checked against the live GST portal, CBIC notifications and current return utilities before filing.</p>'
    : '';
  return `<section class="wi-panel"><div class="lp-section-eyebrow">Official fact-check status</div><h2>Fact-check notes</h2><p><strong>Last fact-checked:</strong> ${factDate}</p>${tax}${gst}<p>This Batch 12 page avoids treating future-dated payroll/form/rule changes as final filing advice. Verify the active form, notification, payroll circular or portal utility before implementation.</p></section>`;
}

function gratuityCalculator() {
  return `<section class="wi-panel"><div class="lp-section-eyebrow">Working calculator</div><h2>Gratuity calculator</h2><p>Estimate gratuity for an employee covered by the Payment of Gratuity Act. Tax exemption still depends on employer type, service period and lifetime exemption already used.</p><div class="wi-calc-grid"><label>Last drawn monthly salary<input id="grSalary" type="number" min="0" value="50000"></label><label>Completed years of service<input id="grYears" type="number" min="0" value="10"></label><label>Actual gratuity received<input id="grActual" type="number" min="0" value="288462"></label><label>Employer type<select id="grEmployer"><option value="private">Private / non-government</option><option value="government">Government</option></select></label></div><button class="wi-calc-button" type="button" id="grRun">Calculate</button><div class="wi-calc-result" id="grResult">Enter values and calculate.</div><p class="wi-small-note">Formula used for covered employees: monthly salary x 15 / 26 x completed years. Private-sector exemption cap is modelled at Rs. 20,00,000; confirm cumulative lifetime use before filing.</p></section>`;
}

function extraScript(page) {
  if (page.slug !== 'blog-gratuity-calculator-india') return '';
  return `<script>
function fmt(n){return 'Rs. '+Math.round(n).toLocaleString('en-IN');}
document.addEventListener('DOMContentLoaded',function(){var b=document.getElementById('grRun');if(!b)return;b.addEventListener('click',function(){var salary=Math.max(0,Number(document.getElementById('grSalary').value||0));var years=Math.max(0,Number(document.getElementById('grYears').value||0));var actual=Math.max(0,Number(document.getElementById('grActual').value||0));var employer=document.getElementById('grEmployer').value;var formula=salary*15/26*years;var exempt=employer==='government'?actual:Math.min(actual,formula,2000000);var taxable=Math.max(0,actual-exempt);document.getElementById('grResult').innerHTML='<strong>Formula gratuity:</strong> '+fmt(formula)+'<br><strong>Exempt amount modelled:</strong> '+fmt(exempt)+'<br><strong>Taxable gratuity:</strong> '+fmt(taxable);});});
</script>`;
}

function schema(page) {
  const url = `https://workindex.co.in/seo-pages/${page.slug}.html`;
  const graph = [
    { '@type': 'Organization', '@id': 'https://workindex.co.in/#organization', name: 'WorkIndex', url: 'https://workindex.co.in' },
    { '@type': 'WebPage', '@id': `${url}#webpage`, url, name: page.title, description: page.meta },
    { '@type': 'BreadcrumbList', itemListElement: [{ '@type': 'ListItem', position: 1, name: 'WorkIndex', item: 'https://workindex.co.in' }, { '@type': 'ListItem', position: 2, name: page.h1, item: url }] },
    { '@type': 'FAQPage', mainEntity: page.faqs.map(([q, a]) => ({ '@type': 'Question', name: q, acceptedAnswer: { '@type': 'Answer', text: a.replace(/<[^>]+>/g, '') } })) }
  ];
  if (/calculator/i.test(page.type) || /calculator/i.test(page.title)) {
    graph.push({ '@type': 'SoftwareApplication', name: page.h1, applicationCategory: 'FinanceApplication', operatingSystem: 'Web', offers: { '@type': 'Offer', price: '0', priceCurrency: 'INR' } });
  } else {
    graph.push({ '@type': 'Service', name: page.h1, serviceType: page.type, provider: { '@id': 'https://workindex.co.in/#organization' }, areaServed: { '@type': 'Country', name: 'India' }, description: page.meta });
  }
  return JSON.stringify({ '@context': 'https://schema.org', '@graph': graph });
}

