function page(slug, type, title, meta, h1, subtitle, summary, points, useCases, records, mistakes, related, refType = 'tax', faqs) {
  if (!Array.isArray(related) && Array.isArray(mistakes)) {
    related = mistakes;
    mistakes = records;
    records = useCases;
    useCases = points;
    points = [
      `${h1} needs year, state, industry and document-specific handling before filing or quoting.`,
      'Compare experts on matching experience, portal familiarity, response time and written deliverables.',
      'Keep source records ready so the expert can verify the facts instead of estimating from memory.'
    ];
  }
  if (!Array.isArray(related)) throw new Error(`${slug} has invalid related links`);
  return {
    slug, type, title, meta, h1, subtitle, summary, points, useCases, records, mistakes, related, refType,
    process: ['Confirm the applicable year, taxpayer type, form, state and portal status before acting.', 'Reconcile portal data with payslips, books, invoices, Form 16/26AS/AIS, GST returns, EPFO records or contracts.', 'Prepare a written computation, filing note, checklist or response with assumptions clearly stated.', 'Download acknowledgements, challans, workings and evidence after filing or submission.'],
    faqs: faqs || [
      ['Can WorkIndex help with this?', 'Yes. Post the facts and documents; relevant experts can quote for filing, advisory, reconciliation, registration, appeal support or ongoing compliance.'],
      ['Is this page final legal advice?', 'No. Use it to prepare. A professional should verify the active law year, notification, portal utility and records before filing or taking a tax position.'],
      ['What should I mention while posting?', 'Mention the year, state, form, deadline, amount involved, documents available, portal status and whether you need filing, correction, advisory or representation.']
    ]
  };
}

